import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const mastra = new Mastra();

mastra.onWorkflowStep(async (step) => {
  const result = await vex.validate({
    data: step.output,
    rules: ['pii_redact', 'privilege_scan'],
    context: { industry: 'legal' }
  });
  if (!result.valid) {
    throw new Error(`Compliance violation: ${result.issues}`);
  }
  return step.output;
});

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
mastra.registerTool('caseResearch', async (query: string) => {
  const rawResult = await researchCases(query);
  const verified = await vex.validate({
    data: rawResult,
    rules: ['legal_citation_verify'],
    context: { db: 'caselaw' }
  });
  if (verified.issues.length > 0) {
    return { error: 'Invalid citations detected', issues: verified.issues };
  }
  return verified.cleanData;
});

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
mastra.onMemoryRetrieve(async (memory) => {
  const audit = await vex.audit({
    data: memory.content,
    rules: ['freshness_check', 'tamper_detect'],
    context: { timestamp: Date.now(), type: 'legal_evidence' }
  });
  if (!audit.fresh || audit.tampered) {
    console.warn('Blocked stale memory:', audit.issues);
    return null;
  }
  return memory;
});
